import{_ as n,c as e,m as a,a as p,t as l,a5 as P,o as r}from"./chunks/framework.DwbewbAn.js";const t="/assets/v2-867d648e45e11acfe4de95a8bb169184_720w.DhgjkQrb.jpg",i="/assets/v2-0dbf837b5d0997d375af80c5ea0d6cf0_720w.C0_VPgg7.jpg",c="/assets/v2-0f908e6191d3726926ba77e81c8573fe_720w.WeK8wUqq.jpg",o="/assets/v2-ae4159808f2962b8aec6c2e917f8366d_720w.DR_Pi5ny.jpg",D="/assets/v2-9b9530f269632f62fc03a9b8a504dcfe_720w.DH9ka9-L.jpg",C=JSON.parse('{"title":"UDP详解","description":"","frontmatter":{"title":"UDP详解"},"headers":[],"relativePath":"doc/网络协议/UDP/UDP.md","filePath":"packages/doc/src/网络协议/UDP/UDP.md","lastUpdated":1704643216000}'),d={name:"doc/网络协议/UDP/UDP.md"},U={id:"frontmatter-title",tabindex:"-1"},b=a("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),h=P(`<p>User Datagram Protocol</p><h2 id="_1-概述" tabindex="-1">1.概述 <a class="header-anchor" href="#_1-概述" aria-label="Permalink to &quot;1.概述&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>UDP是User Datagram Protocol(用户数据报协议)的缩写，它是一个简单的协议，简单到UDP规范RFC0768只有区区3页。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol><li>扩展出端口号使得IP数据报可以多路分发到用户进程。</li><li>扩展出校验和提供网络传输过程中数据差错的检验。</li></ol><h2 id="_2-特性" tabindex="-1">2.特性 <a class="header-anchor" href="#_2-特性" aria-label="Permalink to &quot;2.特性&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>UDP是无连接的，通信之前无须建连便可直接发送数据报，而TCP是面向连接的。</span></span>
<span class="line"><span>UDP不提供差错纠正，但UDP提供差错检测(端到端校验和)。</span></span>
<span class="line"><span>UDP不做重复消除。</span></span>
<span class="line"><span>UDP不做流量控制。</span></span>
<span class="line"><span>UDP不做拥塞控制，没有协议机制防止高速UDP流量对其他网络用户的消极影响。</span></span>
<span class="line"><span>UDP不保证顺序，数据报递交应用的顺序。</span></span>
<span class="line"><span>UDP不可靠，UDP只负责把应用程序传给IP层的数据发送出去，并不能保证数据报到达目的地，可靠传递需要应用程序去实现。</span></span>
<span class="line"><span>UDP支持组播交付。</span></span>
<span class="line"><span>UDP是一种保留消息边界的传输层协议。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>UDP提供不可靠服务，具有TCP所没有的优势：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1.分组首部开销小，TCP首部20字节，UDP首部8字节。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2.UDP无连接，时间上不存在建立连接需要的时延。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3.UDP没有拥塞控制，应用层能够更好的控制要发送的数据和发送时间，网络中的拥塞控制也不会影响主机的发送速率。某些实时应用要求以稳定的速度发送，能容 忍一些数据的丢失，但是不能允许有较大的时延（比如实时视频，直播等）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4.UDP提供尽最大努力的交付，不保证可靠交付。所有维护传输可靠性的工作需要用户在应用层来完成。没有TCP的确认机制、重传机制。如果因为网络原因没有传送到对端，UDP也不会给应用层返回错误信息</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5.UDP是面向报文的，对应用层交下来的报文，添加首部后直接乡下交付为IP层，既不合并，也不拆分，保留这些报文的边界。对IP层交上来UDP用户数据报，在去除首部后就原封不动地交付给上层应用进程，报文不可分割，是UDP数据报处理的最小单位。</span></span>
<span class="line"><span>正是因为这样，UDP显得不够灵活，不能控制读写数据的次数和数量。比如我们要发送100个字节的报文，我们调用一次sendto函数就会发送100字节，对端也需要用recvfrom函数一次性接收100字节，不能使用循环每次获取10个字节，获取十次这样的做法。</span></span>
<span class="line"><span>6.UDP常用一次性传输比较少量数据的网络应用，如DNS,SNMP等，因为对于这些应用，若是采用TCP，为连接的创建，维护和拆除带来不小的开销。UDP也常用于多媒体应用（如IP电话，实时视频会议，流媒体等）数据的可靠传输对他们而言并不重要，TCP的拥塞控制会使他们有较大的延迟，也是不可容忍的</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h2 id="_3-首部格式" tabindex="-1">3.首部格式 <a class="header-anchor" href="#_3-首部格式" aria-label="Permalink to &quot;3.首部格式&quot;">​</a></h2><p>UDP数据报分为<strong>首部</strong>和<strong>用户数据部分</strong>，整个UDP数据报作为IP数据报的数据部分封装在IP数据报中，UDP数据报文结构如图所示：</p><p>UDP首部有8个字节，由4个字段构成，每个字段都是两个字节， 1.源端口（可选）： 源端口号，需要对方回信时选用，不需要时全部置0. 2.目的端口：目的端口号，在终点交付报文的时候需要用到。 3.长度：UDP的数据报的长度（包括首部和数据）其最小值为8（只有首部） 4.校验和：检测UDP数据报在传输中是否有错，有错则丢弃。该字段是可选的，当源主机不想计算校验和，则直接令该字段全为0. 当传输层从IP层收到UDP数据报时，就根据首部中的目的端口，把UDP数据报通过相应的端口，上交给应用进程。 如果接收方UDP发现收到的报文中的目的端口号不正确（不存在对应端口号的应用进程0,），就丢弃该报文，并由ICMP发送“端口不可达”差错报文给对方。</p><h2 id="_4-udp校验" tabindex="-1">4.UDP校验 <a class="header-anchor" href="#_4-udp校验" aria-label="Permalink to &quot;4.UDP校验&quot;">​</a></h2><p>在计算校验和的时候，需要在UDP数据报之前增加12字节的伪首部，伪首部并不是UDP真正的首部。只是在计算校验和，临时添加在UDP数据报的前面，得到一个临时的UDP数据报。校验和就是按照这个临时的UDP数据报计算的。伪首部既不向下传送也不向上递交，而仅仅是为了计算校验和。这样的校验和，既检查了UDP数据报，又对IP数据报的源IP地址和目的IP地址进行了检验。</p><p>UDP校验和的计算方法和IP数据报首部校验和的计算方法相似，都使用二进制反码运算求和再取反，但不同的是：IP数据报的校验和之检验IP数据报和首部，但UDP的校验和是把首部和数据部分一起校验。</p><p>发送方，首先是把全零放入校验和字段并且添加伪首部，然后把UDP数据报看成是由许多16位的子串连接起来，若UDP数据报的数据部分不是偶数个字节，则要在数据部分末尾增加一个全零字节（此字节不发送），接下来就按照二进制反码计算出这些16位字的和。将此和的二进制反码写入校验和字段。在接收方，把收到得UDP数据报加上伪首部（如果不为偶数个字节，还需要补上全零字节）后，按二进制反码计算出这些16位字的和。当无差错时其结果全为1,。否则就表明有差错出现，接收方应该丢弃这个UDP数据报。</p><p>注意： 1.校验时，若UDP数据报部分的长度不是偶数个字节，则需要填入一个全0字节，但是次字节和伪首部一样，是不发送的。 2.如果UDP校验和校验出UDP数据报是错误的，可以丢弃，也可以交付上层，但是要附上错误报告，告诉上层这是错误的数据报。 3.通过伪首部，不仅可以检查源端口号，目的端口号和UDP用户数据报的数据部分，还可以检查IP数据报的源IP地址和目的地址。 这种差错检验的检错能力不强，但是简单，速度快</p><h2 id="_5-消息边界" tabindex="-1">5.消息边界 <a class="header-anchor" href="#_5-消息边界" aria-label="Permalink to &quot;5.消息边界&quot;">​</a></h2><p>应用程序每请求一次UDP输出将产生一个UDP数据报，从而发送一个IP数据报，而接收端每请求一次UDP接收都将接收一个完整的UDP报(如果有)，这跟面向数据流的TCP不一样。</p><p>假设主机A给主机B发送2次数据，***次4字节“abcd”，第二次3字节“xyz”，而主机B接收2次，分别返回“abcd”、“xyz”两个消息，也可以返回“xyz”，“abcd”两个消息(顺序不重要)，那么这就是保留消息边界。</p><p>UDP是保留消息边界的传输层协议，利用UDP通信的应用程序每次发送操作会产生一个IP数据报(不考虑分片)，这就约束每次发送的数据量不能大于MTU(***传输单元)，接收端每次接收都会返回一个个UDP数据报的完整负载，不会出现返回半个数据报负载的情况。</p><p>而TCP是不保留消息边界的流协议，发送端调用发送的次数和每次发送的数据量，跟接收端调用接收的次数和每次接收的数据量，没有任何对应关系，所以使用TCP的应用程序需要去处理消息边界。</p><p><img src="`+t+'" alt="img"></p><h2 id="udp数据报封装格式" tabindex="-1"><strong>UDP数据报封装格式</strong> <a class="header-anchor" href="#udp数据报封装格式" aria-label="Permalink to &quot;**UDP数据报封装格式**&quot;">​</a></h2><p>IPv4协议(Protocol)字段用值17来标识UDP，UDP数据报头部通常是8字节，IPv4头部之后紧接着是UDP头部，然后是UDP数据Payload(如有)。</p><p><img src="'+i+'" alt="img">IPv4 UDP数据报封装格式</p><p>IPv4封装包对应的UDP头部由源端口号、目的端口号、长度、校验和组成，每个字段都是2字节。</p><h3 id="_1、端口号-纯抽象的标识-它不跟任何物理实体相关。" tabindex="-1"><strong>1、端口号，纯抽象的标识，它不跟任何物理实体相关。</strong> <a class="header-anchor" href="#_1、端口号-纯抽象的标识-它不跟任何物理实体相关。" aria-label="Permalink to &quot;**1、端口号，纯抽象的标识，它不跟任何物理实体相关。**&quot;">​</a></h3><p>端口号用于帮助协议分辨发送和接收进程。接收端的内核层从网卡接收到IP数据报之后，识别出UDP数据报(IP数据报头部协议字段值=17)之后，会根据UDP头部的目的端口号，映射到对应进程，把UDP数据报交给对应的进程去处理，这个映射关系由系统内核管理维护。</p><p><img src="'+c+'" alt="img">UDP头部和负载</p><p>目的端口号是必须的，但源端口号是可选的，如果数据报发送者不需要对方回复的话，则源端口号可被设置为0。</p><p>因为IP层根据IP头部的协议类型字段，将进入的IP数据报，分发到特定的传输协议(TCP或UDP等)，到了传输协议层，再根据端口号将协议数据分发到不同进程。所以，端口号是协议独立的，不同协议的相同端口号并不会引起分发混乱。</p><p>比如，一台机器上的两个网络服务进程使用相同的IP地址和端口号，但一个使用TCP协议，另一个使用UDP协议，这样是没有问题。</p><p>2、长度字段，是以字节为单位的UDP头部和UDP数据的总长度，因为UDP头部长度为8，且空数据的UDP数据报是允许的，这意味着该长度字段值最小为8。UDP长度值是冗余的，因为可以通过IP数据报的总长度减去IP首部的长度推导出来。</p><p>3、校验和，覆盖了UDP首部、UDP数据和一个伪首部，由初始发送方计算，由最终目的方校验，用于判断数据报在网络传输过程中是否出错，比如某一位从1变成了0。</p><h2 id="使用udp的应用程序如何实现可靠传输" tabindex="-1"><strong>使用UDP的应用程序如何实现可靠传输</strong> <a class="header-anchor" href="#使用udp的应用程序如何实现可靠传输" aria-label="Permalink to &quot;**使用UDP的应用程序如何实现可靠传输**&quot;">​</a></h2><p>众所周知，UDP不可靠、不保证顺序。</p><p>1、什么叫不可靠?A给B发送一个UDP数据报，该UDP数据报不一定被正确交付给接收端B，但因为网络质量等各种原因，可能丢包，IP数据报是尽力而为的交付，一切随缘。</p><p>有没有办法保证，发送的UDP一定到达目的端?Sorry，保证不了，做不到。</p><p>那TCP提供的可靠传输是什么意思?TCP提供的可靠传输并不是指不丢包，因为TCP也依赖IP(IP不可靠)实现数据报交付，TCP的可靠性是指丢掉的包会被重传，直到被正确投递，才会继续传输下一个数据报。</p><p>那TCP是怎么做到可靠传输的呢?很简单，收报确认(ack)+丢包重传。所以UDP如果要提供可靠传输，也可以参考TCP的实现机制，只是TCP是实现在内核层，而基于UDP的应用程序，可以把可靠传输做到应用层。要做收报确认+丢包重传，需要一些额外的信息，比如包序列号之类，可以放到Payload，约定好这些额外信息在Payload中的结构布局即可。</p><p>2、什么叫不保证顺序?A给B发送两个UDP数据报，两个UDP数据报会被封装为两个IP数据报，通过IP协议传输，因为两个IP数据报独立路由，所以哪个先到?不一定，看心情。</p><p>有没有办法保证，UDP数据报按照发送端发送的时间顺序到达目的端?也Sorry，办不到。</p><p>所以，TCP提供的顺序性，其实只是在接收端对IP数据报根据发送顺序重新排序，很显然，UDP要支持重排序，也需要一些额外信息，也只能通过payload携带，而不能像TCP一样(TCP首部的一些字段用于接收端重排序)。</p><p>综上，UDP只提供最简单端主机上应用程序的端到端服务，其他的特性，如果要提供，那请参考TCP的思路去实现吧。</p><p>这是有好处的：因为简单，所以开销很小。而某些应用场景，可以容忍丢包、乱序，UDP就是很适合的。保时捷是很好，但拉砖还是用拖拉机吧。</p><p><img src="'+o+'" alt="img"></p><h2 id="udp-socket编程" tabindex="-1"><strong>UDP Socket编程</strong> <a class="header-anchor" href="#udp-socket编程" aria-label="Permalink to &quot;**UDP Socket编程**&quot;">​</a></h2><p>UDP Socket网络编程的API不多，socket()用于创建套接字，close()用于关闭套接字，sendto()用于发送数据，recvfrom()用于接收数据。</p><p>bind()顾名思义是绑定，TCP可以绑定，UDP也可以，bind用于UDP等于告诉内核：这个套接字跟网络远端的一个，而没有bind之前，只能通过sendto()接口(通过参数指定目的地)。UDP套接字recv()返回的是UDP数据报的数据部分(Payload)，不包括UDP数据报首部，这是因为UDP首部的字段用于分发或者校验，不需要透传给应用程序。</p><p>使用UDP套接字开发的网络应用Server/Client，网络IO相关操作和流程如下图所示：</p><p><img src="'+D+'" alt="img">UDP套接字编程</p>',50);function m(s,u,_,g,I,f){return r(),e("div",null,[a("h1",U,[p(l(s.$frontmatter.title)+" ",1),b]),h])}const k=n(d,[["render",m]]);export{C as __pageData,k as default};
